  "poster-basic": [
    { name: "Demo", code: "<PosterFrameMockup deviceProps={{ rotation: [0, 0.25, 0] }}>\n  <PosterArt />\n</PosterFrameMockup>" },
    { name: "PosterArt", code: "export function PosterArt() {\n  return (\n    <div\n      style={{\n        width: '100%',\n        height: '100%',\n        boxSizing: 'border-box',\n        padding: 30,\n        background: 'linear-gradient(200deg, #f5e9d4 0%, #f2ddb8 100%)',\n        color: '#1c1a16',\n        display: 'flex',\n        flexDirection: 'column',\n        overflow: 'hidden',\n      }}\n    >\n      <div style={{ fontSize: 12, letterSpacing: 4 }}>LIVE AT THE FOUNDRY</div>\n      <div style={{ fontSize: 76, fontWeight: 800, lineHeight: 0.94, letterSpacing: -3, marginTop: 18 }}>\n        SIGNAL\n        <br />\n        <span style={{ color: '#d1461f' }}>/ NOISE</span>\n      </div>\n      <svg viewBox=\"0 0 100 26\" aria-hidden style={{ width: '100%', marginTop: 'auto' }}>\n        {Array.from({ length: 40 }, (_, i) => (\n          <rect key={i} x={i * 2.5} y={13 - Math.abs(Math.sin(i * 0.55)) * 11} width={1.4} height={Math.abs(Math.sin(i * 0.55)) * 22 + 2} fill=\"#1c1a16\" />\n        ))}\n      </svg>\n      <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, fontWeight: 600, marginTop: 16 }}>\n        <span>SAT AUG 22 · 9PM</span>\n        <span>DOORS 8PM · ALL AGES</span>\n      </div>\n    </div>\n  )\n}" },
  ],
  "poster-oak": [
    { name: "Demo", code: "<PosterFrameMockup color=\"#b98d5f\" posterBackground=\"#f7f2e8\" float deviceProps={{ rotation: [0, -0.25, 0] }}>\n  <MiniCover title=\"Form & Counterform\" from=\"#e6dccb\" to=\"#cdbb92\" />\n</PosterFrameMockup>" },
    { name: "MiniCover", code: "function MiniCover({ title, from, to }: { title: string; from: string; to: string }) {\n  return (\n    <div\n      style={{\n        width: '100%',\n        height: '100%',\n        boxSizing: 'border-box',\n        padding: 20,\n        background: `linear-gradient(165deg, ${from}, ${to})`,\n        color: '#fff',\n        display: 'flex',\n        flexDirection: 'column',\n        justifyContent: 'flex-end',\n        fontWeight: 700,\n        fontSize: 24,\n        lineHeight: 1.1,\n      }}\n    >\n      {title}\n    </div>\n  )\n}" },
  ],
